import React from "react";
import "./index.css";
import Item from "../../components/Item";
import { RouteComponentProps } from "@reach/router";

export default function Award(props: RouteComponentProps) {
  const scholarships = [
    {
      title: "SFU Alumni Scholarship",
      subTitle: "Simon Fraser University",
      time: "Fall 2017"
    },
    {
      title: "SFU Alumni Scholarship",
      subTitle: "Simon Fraser University",
      time: "Spring 2017"
    },
    {
      title: "SFU Alumni Scholarship",
      subTitle: "Simon Fraser University",
      time: "Summer 2017"
    }
  ];
  const awards = [
    {
      title: "Dean's Honour Roll",
      subTitle: "Simon Fraser University",
      time: "Fall 2017"
    },
    {
      title: "Dean's Honour Roll",
      subTitle: "Simon Fraser University",
      time: "Spring 2017"
    },
    {
      title: "Dean's Honour Roll",
      subTitle: "Simon Fraser University",
      time: "Summer 2017"
    }
  ];

  return (
    <div className="main">
      <div className="scholarship">
        <p className="sectionTitle">Scholarships</p>
        {scholarships.map(scholarship => {
          return <Item {...scholarship} />;
        })}
      </div>
      <div className="awards">
        <p className="sectionTitle">Awards</p>
        <p className="description">
          A limited number of students will be admitted each term to the Dean's
          Honour Roll, mainly on the basis of excellent work completed in the
          previous term.
        </p>
        {awards.map(award => {
          return <Item {...award} />;
        })}
      </div>
    </div>
  );
}
