import React from "react";
import { Link } from "@reach/router";
import "./index.css";
import * as projectURL from "../../constant";

export default function Header(props: any) {
  return (
    <header className="header">
      <NavLink to="/">Home</NavLink>
      <NavLink to="resume">Resume</NavLink>
      <a href={projectURL.blogURL} target="_blank" rel="noopener noreferrer">
        Blog
      </a>
    </header>
  );
}

function NavLink(props: any) {
  return (
    <Link
      {...props}
      getProps={({ isCurrent }) => {
        return {
          style: {
            color: isCurrent ? "lightslategray" : "chocolate",
          },
        };
      }}
    />
  );
}
