import React from "react";
import { Router, LocationProvider, createHistory } from "@reach/router";
import createHashSource from "hash-source";
import "./App.css";
import Header from "./components/Header";
import Home from "./views/Home";
import Footer from "./components/Footer";
import Award from "./views/Award";
import Education from "./views/Education";
import Resume from "./views/Resume";
import Projects from "./views/Projects";
import AcademicProjects from "./views/AcamedicProjects";

let source: any = createHashSource();
let history = createHistory(source);

const App = () => {
  return (
    <div className="App">
      <LocationProvider history={history}>
        <Header />
        <Router>
          <Home path="/" />
          <Award path="/award" />
          <Education path="/education" />
          <Resume path="/resume" />
          <Projects path="/projects" />
          <AcademicProjects path="/aca_projects" />
        </Router>
        <Footer />
      </LocationProvider>
    </div>
  );
};

export default App;
