import React from "react";
import "./index.css";

interface Props {
  img: string;
  name: string;
  icon?: string;
  type?: string;
  technology?: string;
  description: string;
  url?: string;
}

export default function Project(props: Props) {
  return (
    <div className="project" onClick={() => window.open(props.url)}>
      <img src={props.icon} alt="technology" className="icon" />
      <div className="description">
        <p className="title">{props.name.toUpperCase()}</p>
        <p className="title">
          <img src={props.img} alt="project screenshot" />
        </p>
        <p className="subTitle">{props.type}</p>
        <p>{props.description}</p>
      </div>
    </div>
  );
}
