import React, { useState, useEffect } from "react";
import "./index.css";
import NavBlock from "../../components/NavBlock";
import { RouteComponentProps } from "@reach/router";

export default function Home(props: RouteComponentProps) {
  const [expanded, setExpanded] = useState(true);

  function toggleExpanded() {
    setExpanded(!expanded);
  }

  useEffect(() => {
    window.scrollTo({ top: 0 });
  }, []);

  return (
    <main>
      <div className={expanded ? "home active" : "home inactive"}>
        {expanded && (
          <div className="itemGroup">
            <NavBlock
              color="rgb(112, 126, 230)"
              title="Projects"
              link="projects"
            />
            <NavBlock
              color="rgb(178, 34, 34)"
              title="Education"
              link="education"
            />
          </div>
        )}
        <img
          src={require("../../assets/logo.png")}
          alt="logo"
          onClick={toggleExpanded}
          className="blink"
        />
        {expanded && (
          <div className="itemGroup">
            <NavBlock
              color="rgb(150, 109, 42)"
              title="Academic Projects"
              link="aca_projects"
            />
            <NavBlock
              color="rgb(81, 143, 188)"
              title="Award/ Scholarship"
              link="award"
            />
          </div>
        )}
      </div>
      <div className="introduction">
        <div style={{ margin: 10 }}>
          <strong>Welcome to my e-porfolio.</strong>
          <p>
            My name is <strong> Tu Dat Nguyen</strong>. I am a computer
            scientist who loves to discuss algorithms. If you ask me about my
            favorite programming language, my answer is not C, C#, Java,
            JavaScript or else but
            <strong> pseudocode</strong>. Instead of picking one programming
            language or framework to master, I like to use my strong computing
            background to explore different alternatives so that I can pick the
            best for projects. If you need a{" "}
            <strong> C, C#, C++, JavaScript, or Python </strong>
            developer having experience with{" "}
            <strong>
              {" "}
              Firebase, Node Js, Express Js, ASP.Net Core, or Django
            </strong>
            , I am happy to become a member of your team.
          </p>
          <p>Please click above links to know more about me.</p>
        </div>
      </div>
    </main>
  );
}
