import React from "react";
import { Link } from "@reach/router";
import "./index.css";

interface Props {
  color: string;
  title: string;
  link: string;
  className?: string;
}

export default function NavBlock(props: Props) {
  return (
    <div
      className={"navBlock " + props.className}
      style={{ backgroundColor: props.color }}
    >
      <Link to={props.link}>{props.title}</Link>
    </div>
  );
}
