import React, { useEffect } from "react";
import "./index.css";
import { RouteComponentProps, Link } from "@reach/router";
import Contact from "../../components/Contact";
import Item from "../../components/Item";
import * as projectURL from "../../constant";
import { projects } from "../Projects";

export default function Resume(props: RouteComponentProps) {
  useEffect(() => {
    window.scrollTo({ top: 0 });
  }, []);
  return (
    <div className="resume">
      <div className="sidebar">
        <div className="contact">
          <img src={require("../../assets/logo.png")} alt="Avatar" />
          <Contact />
        </div>
      </div>
      <div className="content">
        <h2>Technical Skills</h2>
        <div className="technical">
          <div className="skills languages">
            <h3>Programming Languages</h3>
            <ul>
              <li>C/ C++/ C#</li>
              <li>Python</li>
              <li>JavaScript/ HTML/ CSS</li>
              <li>SQL</li>
              <li>Swift</li>
            </ul>
          </div>
          <div className="skills frameworks">
            <h3>Frameworks</h3>
            <ul>
              <li>
                <a
                  href="https://tudatn.github.io"
                  target="_blank"
                  rel="noopener noreferrer"
                >
                  React
                </a>
              </li>
              <li>React Native</li>
              <li>
                <a
                  href={projectURL.blogURL}
                  target="_blank"
                  rel="noopener noreferrer"
                >
                  Django
                </a>
              </li>
              <li>Ruby on Rails</li>
              <li>ASP.Net Core</li>
              <li>
                <a
                  href={projectURL.spartyURL}
                  target="_blank"
                  rel="noopener noreferrer"
                >
                  Express JS
                </a>
              </li>
            </ul>
          </div>
          <div className="skills platforms">
            <h3>Development Platforms/ Tools</h3>
            <ul>
              <li>Linux/ MacOS/ Windows</li>
              <li>Visual Studio (Code)</li>
              <li>Atom/ Eclipse</li>
              <li>Xcode</li>
              <li>Unity</li>
            </ul>
          </div>
        </div>
        <hr />
        <h2>Transferable Skills</h2>
        <div className="transferable">
          <ul>
            <li>
              Quick learner; able to take on new challenges with a strong sense
              of responsibility and self-motivation
            </li>
            <li>
              Able to break complex problems into smaller and solvable
              sub-problems
            </li>
            <li>
              Experience in leading and coordinating related teams to complete
              given tasks
            </li>
          </ul>
        </div>
        <hr />
        <h2>Experience</h2>
        <div className="experience">
          <Item
            title="Software Developer"
            subTitle="Affinity Bridge"
            time="Sept. 2019 - Current"
            details={
              <ul>
                <li>
                  Develop web applications including BackEnd (Django, Ruby on
                  Rails) and FrontEnd (React)
                </li>
                <li>
                  Develop mobile applications with React Native using a variety
                  of serverside technologies including Firebase, Django APIs
                </li>
                <li>
                  Research and develop new technologies and stacks for the
                  company
                </li>
                <li>
                  Develop continuous integration and delivery process for
                  existing and new projects using Gitlab CI/CD and automation
                  tools (Ansible, bash script)
                </li>
              </ul>
            }
          />
          <Item
            title="Coop QA Analyst"
            subTitle="PNI Digital Media"
            time="Sept. 2018 - Apr. 2019"
            details={
              <ul>
                <li>Create and run test cases on TestRail</li>
                <li>
                  Create UI automation scripts using Selenium/ Specflow on
                  Visual Studio
                </li>
                <li>
                  Develop the test plan based on Business Requirement Document
                </li>
                <li>
                  Coordinate with other developers to address and solve bugs
                </li>
              </ul>
            }
          />
        </div>
        <hr />
        <h2>
          <Link to="/">Projects</Link>
        </h2>
        <div className="projectSection">
          {projects.map((project) => {
            return (
              <div className="projectItem">
                <a href={project.url} target="_blank" rel="noopener noreferrer">
                  <h3>{project.name}</h3>
                </a>
                <p>{project.description}</p>
              </div>
            );
          })}
        </div>
        <hr />
        <h2>
          <Link to="education">Education</Link>
        </h2>
        <Item
          title="Bachelor of Science - Computing Science"
          subTitle="Simon Fraser University"
          time="(2016 - 2019)"
        />
        <hr />
        <h2>
          <Link to="award">Award</Link>
        </h2>
        <Item
          title="SFU Alumni Scholarship"
          subTitle="Simon Fraser University"
          time="(Fall 2017, Summer 2018, Spring 2018)"
        />
        <Item
          title="Dean's Honour Roll"
          subTitle="Simon Fraser University"
          time="(Fall 2017, Summer 2018, Spring 2018)"
        />
        <hr />
        <h2>Freetime</h2>
        <ul>
          <li>Making tutorial videos</li>
          <li>Solving problems on LeetCode/ A2 Online</li>
          <li>Playing soccer</li>
        </ul>
      </div>
    </div>
  );
}
